import{_ as o,o as e,c as n,a2 as t}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"G03: 核心員工流動率審計","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/經營組/G03_核心員工流動率審計_績效管理專家.md","filePath":"32Ｑ題本＿重要/經營組/G03_核心員工流動率審計_績效管理專家.md"}'),i={name:"32Ｑ題本＿重要/經營組/G03_核心員工流動率審計_績效管理專家.md"};function l(s,r,a,g,d,_){return e(),n("div",null,[...r[0]||(r[0]=[t('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="g03-核心員工流動率審計" tabindex="-1">G03: 核心員工流動率審計 <a class="header-anchor" href="#g03-核心員工流動率審計" aria-label="Permalink to &quot;G03: 核心員工流動率審計&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-G03</li><li><strong>題目：</strong> 核心技術或研發團隊的流動率為何？公司如何留住優秀人才？是否有關鍵人才流向競爭對手的跡象？</li><li><strong>推薦專家：</strong> 績效管理專家 (<code>hr-performance-reviewer</code>)</li><li><strong>推薦理由：</strong> 專精於「組織能力審計」與「人力資本價值評估」。具備從招聘資料、薪酬水位與離職趨勢中讀取企業「技術護城河」是否正在潰散的能力。其核心職責是在業績爆雷前，先從「人才流變」中識別出企業衰敗的早期徵兆。</li><li><strong>意圖：</strong> 執行「組織韌性與人才護城河審計」。透過量化員工流動率與分析關鍵人才去向，判定企業的技術延續性與知識管理能力，識別因「人才失血」而造成的研發延宕或客戶流失風險。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【第一優先：FinMind】</strong>：調用 <code>TaiwanStockFinancialStatements</code> 提取「員工福利費用」並對比員工人數，計算「人均薪資」與「人均獲利」之三年趨勢。</li><li><strong>【第二優先：永續報告書 (CSR/ESG)】</strong>：從 <strong>MOPS</strong> 下載最新的「環境、社會及治理報告」。提取「全體員工離職率」與「核心技術/研發人員離職率」之年度對比數據。</li><li><strong>【第三優先：職場社群與招聘網站】</strong>：檢索 <strong>LinkedIn / 104 人力銀行 / Glassdoor</strong>。觀察關鍵職務的懸掛天數與員工評價。</li><li><strong>【最後手段：Web Search】</strong>：檢索「[公司名] 高管 離職」、「[公司名] 挖角 訴訟」。</li></ol></li><li><strong>邏輯：</strong> 執行「HCROI (人力資本回報率) 相關性審計」——計算 <code>(淨利 + 員工福利費用) / 員工福利費用</code>。若流動率高但 HCROI 上升，判定為組織排毒；執行「技術空洞化壓力測試」。</li><li><strong>來源：</strong> <code>FinMind (人均薪資)</code>, <code>CSR 報告 (永續報告書)</code>, <code>104/LinkedIn (職位掛缺週期)</code>, <code>Glassdoor (組織文化評價)</code></li></ul><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【人力資本效能檢測】</strong>：智慧體必須計算「人均營收 (Revenue per Employee)」與「人均獲利」。若員工流動率上升但人均產值成長 &gt; 10%，應改寫評語為「組織效率優化」。</li><li><strong>【核心缺口追蹤】</strong>：智慧體必須查驗 LinkedIn 或 104 是否有大量「關鍵資深職位」同時釋出。若公司核心 R&amp;D 同步離職且被頭號對手錄取，必須發出「技術洩漏與競爭力下降」的嚴厲警告。</li><li><strong>【薪酬競爭力勾稽】</strong>：對照 FinMind 中的平均薪資與同業基準。若薪資低於同業中位數且流動率高，判定為「人才庫正被競爭對手收割」。</li><li><strong>【描述指標】</strong>：絕對禁用「員工流動率正常」。必須明確指出「是否足以滿足未來產能或 R&amp;D 擴張需求」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【g03-專家答詢】績效管理專家-hr-performance-reviewer" tabindex="-1">【G03 專家答詢】績效管理專家 (hr-performance-reviewer) <a class="header-anchor" href="#【g03-專家答詢】績效管理專家-hr-performance-reviewer" aria-label="Permalink to &quot;【G03 專家答詢】績效管理專家 (hr-performance-reviewer)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「動態定性+業績關聯」結構（例：該公司員工流動率穩定，且人均獲利成長優於同業，顯示 [組織韌性強] ；雖有局部高管異動，但 [梯隊接班健全] ）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：流動率極低，人均產值創歷史新高，人才磁吸力強。</li><li><strong>A (良)</strong>：流動率處於行業正常範圍，核心技術團隊穩定，招聘達成率高。</li><li><strong>B (持平)</strong>：流動率偏高或核心人才頻繁異動，人均產值停滯，面臨知識管理斷代風險。</li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐，嚴禁脫離數據空泛推論。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確列出 CSR 報告頁碼、LinkedIn 觀測到的異動趨勢或 FinMind 薪資對比。</li></ul>',9)])])}const p=o(i,[["render",l]]);export{h as __pageData,p as default};
